:root {
  --highlight-color-size: 15px;
}
atom-overlay.highlight-color {
  z-index: 0 !important;
}
.tab-bar {
  z-index: 1;
}
.highlight-color-container {
  position: absolute;
  top: calc(var(--highlight-color-line-height) * -1);
  left: calc(var(--highlight-color-size) / 2);
  height: var(--highlight-color-line-height);
  display: flex;
  align-items: center;
  pointer-events: none;
}
.highlight-color-container.interactive .highlight-color-item {
  pointer-events: auto;
  cursor: pointer;
}
.highlight-color-item {
  position: relative;
  width: var(--highlight-color-size);
  height: var(--highlight-color-size);
  border-radius: calc(var(--highlight-color-size) / 2);
  background-color: #fff;
  background-image: url('data:image/png;base64,%3D%3D');
  background-position: center;
  background-size: calc(var(--highlight-color-size) * 0.3);
  image-rendering: pixelated;
  box-shadow: 0 0 0 1px white;
  overflow: hidden;
}
.highlight-color-item::after {
  content: '';
  display: block;
  width: inherit;
  height: inherit;
  border-radius: inherit;
  box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.3) inset;
  background-color: var(--highlight-color-color);
}
.highlight-color-item + .highlight-color-item {
  margin-left: calc(var(--highlight-color-size) / 2);
}
